+
+    if (meta_->config->lambda_l1 > 0) {
+      if (meta_->config->max_delta_step > 0) {
+        int_find_best_threshold_fun_ = [=] (LAMBDA_PARAMS_INT) {
+          if (hist_bits_acc <= 16) {
